import{c as o,Q as t,j as i,m as a}from"./chunks/framework.CdiUUa3G.js";const p=JSON.parse('{"title":"ADR-057 — Narrow exception to \\"no client storage\\": one functional cookie for explicit user-set locale override","description":"","frontmatter":{},"headers":[],"relativePath":"adr/ADR-057.md","filePath":"adr/ADR-057.md"}'),s={name:"adr/ADR-057.md"};function r(n,e,c,l,d,u){return t(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="adr-057-—-narrow-exception-to-no-client-storage-one-functional-cookie-for-explicit-user-set-locale-override" tabindex="-1">ADR-057 — Narrow exception to &quot;no client storage&quot;: one functional cookie for explicit user-set locale override <a class="header-anchor" href="#adr-057-—-narrow-exception-to-no-client-storage-one-functional-cookie-for-explicit-user-set-locale-override" aria-label="Permalink to &quot;ADR-057 — Narrow exception to &quot;no client storage&quot;: one functional cookie for explicit user-set locale override&quot;">​</a></h1><blockquote><p>Status · Accepted Date · 2026-05-10 Supersedes (in part) · TA.md &quot;no cookies for user preferences&quot; line (lines 159 and 281); narrows the absolute prohibition to a scoped exception Related ADRs · ADR-017 (i18n architecture), ADR-024 (URL-as-state for missions), ADR-029 (PWA + visit-counter in runtime memory), ADR-044 (URL-as-state for locale), ADR-055 (Science Lens — runtime-only) Closes · Issue #73 Gap 2 (cross-session persistence for explicit locale override)</p></blockquote><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>Issue #73 surfaced a friction point in Orrery&#39;s &quot;no client storage&quot; stance: a user who explicitly picks a non-default locale via the LocalePicker loses that preference on a fresh visit. Auto-detection from <code>navigator.language</code> works on first paint (already shipped in <code>src/lib/locale.ts:resolveLocale</code>), and bookmarks carry <code>?lang=</code> cleanly, but a user who <em>overrides</em> their browser default and later types the bare URL again falls back to <code>navigator.language</code>.</p><p>Five existing ADRs and TA.md treat client storage as a hard non-negotiable:</p><ul><li>TA.md:159 — <em>&quot;No user data. No accounts. No login. No <code>localStorage</code>. No <code>sessionStorage</code>. No cookies for user preferences. State is session-only and resets on reload.&quot;</em></li><li>ADR-017 — i18n architecture: locale lives in <code>?lang=</code> URL param.</li><li>ADR-024 — mission URL contract: <code>/fly?mission=id</code> is the only mission state; rejected &quot;last visited mission&quot; because it would need localStorage.</li><li>ADR-029 — PWA visit counter held in <strong>runtime memory only</strong> &quot;per CLAUDE.md &#39;do not use localStorage&#39;.&quot;</li><li>ADR-044 — <em>&quot;Keep <code>?lang=</code> as locale source-of-truth; no storage-based locale state.&quot;</em></li><li>ADR-055 — Science Lens deliberately ephemeral; lens-on resets on every page load. Considered a cookie, rejected as &quot;fights &#39;no localStorage&#39; spirit.&quot;</li></ul><p>The rule has paid dividends: the codebase has stayed disciplined, no GDPR cookie banner is needed, the app has zero compliance surface, multi-device sharing works because URL = canonical state. Removing the rule wholesale would invite scope creep — once one cookie exists, &quot;just one more for X?&quot; becomes a recurring conversation that erodes the simplicity.</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><p><strong>Allow exactly one cookie</strong>, scoped narrowly to the case the absolute rule was actively hurting.</p><h3 id="the-exception" tabindex="-1">The exception <a class="header-anchor" href="#the-exception" aria-label="Permalink to &quot;The exception&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Field</th><th>Value</th></tr></thead><tbody><tr><td>Name</td><td><code>orrery_locale</code></td></tr><tr><td>Value</td><td>A supported locale code from <code>SUPPORTED_LOCALES</code> (e.g. <code>nl</code>, <code>de</code>, <code>sr-Cyrl</code>) — never anything else</td></tr><tr><td><code>SameSite</code></td><td><code>Lax</code></td></tr><tr><td><code>Secure</code></td><td><code>true</code> (production builds; omitted on <code>http://localhost</code> for dev)</td></tr><tr><td><code>HttpOnly</code></td><td><code>false</code> (must be readable from <code>document.cookie</code> — there is no server)</td></tr><tr><td><code>Max-Age</code></td><td><code>31536000</code> (365 days)</td></tr><tr><td><code>Path</code></td><td><code>/</code></td></tr><tr><td>Set when</td><td>The user explicitly clicks a locale in <code>LocalePicker.svelte</code></td></tr><tr><td><strong>Never</strong> set when</td><td>Auto-detection runs (URL canonicalisation per #73 Gap 1 stays cookie-free); page load; SW install; any non-explicit interaction</td></tr></tbody></table><h3 id="resolution-precedence-updates-src-lib-locale-ts-resolvelocale" tabindex="-1">Resolution precedence (updates <code>src/lib/locale.ts:resolveLocale</code>) <a class="header-anchor" href="#resolution-precedence-updates-src-lib-locale-ts-resolvelocale" aria-label="Permalink to &quot;Resolution precedence (updates `src/lib/locale.ts:resolveLocale`)&quot;">​</a></h3><ol><li><code>?lang=</code> in URL — wins always (preserves URL-as-truth + share-link semantics).</li><li><strong><code>orrery_locale</code> cookie</strong> — new, sits between URL and browser.</li><li><code>navigator.language</code> (via <code>normaliseBrowserLocale</code>) — unchanged.</li><li><code>DEFAULT_LOCALE</code> (en-US) — unchanged.</li></ol><h3 id="constraints-on-what-this-exception-unlocks" tabindex="-1">Constraints on what this exception unlocks <a class="header-anchor" href="#constraints-on-what-this-exception-unlocks" aria-label="Permalink to &quot;Constraints on what this exception unlocks&quot;">​</a></h3><p>This ADR is <strong>explicitly scoped to locale overrides only</strong>. It does <strong>not</strong> open the door to:</p><ul><li>Cookies for Science Lens state (ADR-055 still binding).</li><li>Cookies for last-visited mission (ADR-024 still binding).</li><li>Cookies for filter state on <code>/missions</code> or <code>/library</code>.</li><li>Cookies for PWA install-prompt visit counter (ADR-029 still binding).</li><li>Any analytics / tracking cookie of any kind.</li><li>Any cookie that stores anything other than a single locale code.</li></ul><p>Future expansion to cover any of the above requires its own ADR with explicit reasoning. The default answer for any new &quot;should we cookie X?&quot; question stays <em>no</em>.</p><h3 id="compliance" tabindex="-1">Compliance <a class="header-anchor" href="#compliance" aria-label="Permalink to &quot;Compliance&quot;">​</a></h3><p>The cookie is a <strong>strictly necessary / functional preference cookie</strong> under ePrivacy Directive (EU 2002/58/EC, as amended) and GDPR Recital 30. It stores only a UI preference the user explicitly set, contains no personal data, no identifier, no tracking. <strong>No consent banner is required.</strong> Documented in <code>/credits</code> (or a new <code>/privacy</code> blurb if the landing-page work in #74 adds one).</p><h3 id="implementation-surface" tabindex="-1">Implementation surface <a class="header-anchor" href="#implementation-surface" aria-label="Permalink to &quot;Implementation surface&quot;">​</a></h3><ul><li><code>src/lib/locale.ts</code> — add <code>readLocaleCookie()</code> and <code>writeLocaleCookie()</code> helpers; extend <code>resolveLocale()</code> to consult the cookie between URL and <code>navigator.language</code>.</li><li><code>src/lib/components/LocalePicker.svelte</code> — call <code>writeLocaleCookie(code)</code> on click, alongside the existing URL update.</li><li><code>src/lib/locale.test.ts</code> — unit tests for the resolution precedence and the cookie helpers.</li><li><code>tests/e2e/i18n-cookie-persistence.spec.ts</code> — new e2e: pick Italian → fresh navigation to bare URL → still Italian.</li><li>Update <code>CLAUDE.md</code> &quot;Do not use <code>localStorage</code> or <code>sessionStorage</code>&quot; line to add a parenthetical: <em>&quot;and no cookies for user preferences except as narrowly permitted by ADR-057 (explicit locale override only).&quot;</em></li><li>Update <code>docs/adr/TA.md</code> line 159 with the same parenthetical + a link to this ADR.</li><li>Update <code>docs/adr/index.md</code> to add this ADR.</li></ul><p><strong>Estimate:</strong> ~80 LOC across helpers + LocalePicker; 3 unit tests; 1 e2e test; 4 doc updates.</p><h2 id="rationale" tabindex="-1">Rationale <a class="header-anchor" href="#rationale" aria-label="Permalink to &quot;Rationale&quot;">​</a></h2><p>The 2026 norm for locale persistence is functional cookie + URL precedence + <code>navigator.language</code> fallback (GitHub, Google, Wikipedia, MDN, Cloudflare-fronted sites all do this). <code>localStorage</code> itself has fallen out of fashion industry-wide for state of this kind — synchronous API, 5 MB string-only limit, replaced by IndexedDB or just-not-stored for most modern apps. The principled path is therefore <em>not</em> &quot;relax the rule to allow <code>localStorage</code>&quot; but &quot;narrowly allow the modern, tightly-scoped pattern.&quot;</p><p>Keeping the cookie scope to a single key with a single allowed value class is the difference between &quot;Orrery has a preferences subsystem&quot; (slippery slope) and &quot;Orrery remembers one explicit user choice&quot; (bounded, defensible, easy to remove).</p><h2 id="alternatives-considered" tabindex="-1">Alternatives considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives considered&quot;">​</a></h2><ul><li><strong>Status quo (URL-only).</strong> Simplest. Costs one user friction point (override loss on fresh URL) that 95%+ of users will never hit because auto-detect already serves them correctly. Revisit if user feedback shows the friction matters.</li><li><strong><code>localStorage</code> instead of cookie.</strong> Slightly cleaner API but: (1) blocks main thread, (2) industry has moved away, (3) no advantage over a cookie for a single-string preference, (4) feels heavier given the rule history.</li><li><strong>IndexedDB.</strong> Massively over-engineered for one string. Reject.</li><li><strong>Service Worker cache as state store.</strong> Misuses the SW. Reject.</li><li><strong>Server-side (e.g. Cloudflare Worker setting <code>Set-Cookie</code>).</strong> Requires a backend. Violates TA.md &quot;browser-only&quot; non-negotiable. Reject.</li><li><strong>Open the rule wholesale (&quot;allow client storage where useful&quot;).</strong> Loses the discipline that has kept the codebase clean. Reject — preserve the &quot;default is no&quot; stance.</li></ul><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><p><strong>Positive:</strong></p><ul><li>Closes the only legitimate friction the absolute no-storage rule was creating.</li><li>Keeps Orrery&#39;s &quot;share by URL&quot; promise intact (URL still wins).</li><li>Preserves zero-tracking / no-banner stance.</li><li>Establishes a clear precedent for narrow exceptions: <em>one cookie, one purpose, one ADR each.</em></li></ul><p><strong>Negative:</strong></p><ul><li>Introduces a storage primitive that the project had been disciplined about avoiding. Future &quot;just one more cookie?&quot; requests must be refused absent their own ADR — the maintainer must enforce this.</li><li>Adds ~80 LOC + a doc to maintain.</li><li>Adds a test surface (the e2e cookie-persistence spec) that needs Playwright cookie context.</li><li>Slightly complicates the &quot;I cleared my cookies&quot; debugging story — users who clear cookies will revert to <code>navigator.language</code>. Acceptable; clearly documented in <code>/credits</code>.</li></ul><h2 id="decision-status" tabindex="-1">Decision status <a class="header-anchor" href="#decision-status" aria-label="Permalink to &quot;Decision status&quot;">​</a></h2><p><strong>Accepted on 2026-05-10.</strong> Implementation lands in the same PR — see <code>src/lib/locale.ts</code> (<code>readLocaleCookie</code> / <code>writeLocaleCookie</code> / updated <code>resolveLocale</code> precedence), <code>src/lib/components/LocalePicker.svelte</code> (cookie write on <code>pick()</code>), <code>src/lib/locale.test.ts</code> (unit tests), and <code>tests/e2e/i18n-cookie-persistence.spec.ts</code> (e2e coverage of the persistence + sharing-semantics scenarios).</p>',34)])])}const g=o(s,[["render",r]]);export{p as __pageData,g as default};
